import { ApiProperty, ApiPropertyOptional } from "@nestjs/swagger";

import { AbstractDto } from "../../../common/dto/abstract.dto.ts";
import { PaymentStatus } from "../../../constants/payment-status.ts";
import type { PaymentEntity } from "../payment.entity.ts";

export class PaymentDto extends AbstractDto {
  @ApiProperty({ description: "Payment amount" })
  amount!: number;

  @ApiProperty({ description: "Currency code", example: "BTN" })
  currency!: string;

  @ApiProperty({ enum: PaymentStatus, description: "Payment status" })
  status!: PaymentStatus;

  @ApiPropertyOptional({ description: "Transaction ID from gateway" })
  transactionId?: string;

  @ApiPropertyOptional({ description: "Gateway reference number" })
  gatewayReference?: string;

  @ApiPropertyOptional({ description: "Payment description" })
  description?: string;

  @ApiPropertyOptional({ description: "Error message if payment failed" })
  errorMessage?: string;

  @ApiProperty({ description: "User ID who made the payment" })
  userId!: string;

  @ApiPropertyOptional({ description: "Associated pool ID" })
  poolId?: string;

  constructor(payment: PaymentEntity) {
    super(payment);
    this.amount = payment.amount;
    this.currency = payment.currency;
    this.status = payment.status;
    this.transactionId = payment.transactionId;
    this.gatewayReference = payment.gatewayReference;
    this.description = payment.description;
    this.errorMessage = payment.errorMessage;
    this.userId = payment.userId;
    this.poolId = payment.poolId;
  }
}
